fn bls12377_from_le_bytes(bytes: [u8; 32]) -> Bls12377Fr {
    let mut repr = <FFBls12377Fr as FFPrimeField>::Repr::default();
    for (i, digit) in repr.0.as_mut().iter_mut().enumerate() {
        *digit = bytes[i];
    }
    let value = FFBls12377Fr::from_repr(repr);
    if value.is_some().into() {
        Bls12377Fr { value: value.unwrap() }
    } else {
        panic!("Invalid field element")
    }
}

pub fn bls12377_poseidon2_rc3() -> &'static Vec<[Bls12377Fr; 3]> {
    static RC: OnceLock<Vec<[Bls12377Fr; 3]>> = OnceLock::new();
    RC.get_or_init(|| {
        RC3_LE_BYTES
            .iter()
            .map(|row| {
                [
                    bls12377_from_le_bytes(row[0]),
                    bls12377_from_le_bytes(row[1]),
                    bls12377_from_le_bytes(row[2]),
                ]
            })
            .collect()
    })
}
